/* ===========================================================================
 * Event wiring: debounce, Enter, Escape, clear-button click
 * ========================================================================= */
describe('startApp search area events', () => {
  describe('debounced input listener (200 ms)', () => {
    // Fake timers are engaged AFTER the real-timer `await flush()` so the
    // initial render (started by setup → startApp → init → render) can settle
    // using real microtask/timer scheduling. The debounce timer is created
    // only when an `input` event is dispatched below, i.e. after the switch.
    afterEach(() => {
      vi.useRealTimers();
    });

    it('does not search synchronously when the input changes', async () => {
      const { searchInput } = setupSearchWrapper({ hash: toBrowseHash('docs') });
      await flush();
      vi.useFakeTimers();

      searchInput.value = 'hello';
      searchInput.dispatchEvent(new Event('input'));

      // Synchronously after the input event: still browsing.
      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });

    it('fires doSearch once 200 ms have elapsed since the last keystroke', async () => {
      const { searchInput } = setupSearchWrapper({ hash: toBrowseHash('docs') });
      await flush();
      vi.useFakeTimers();

      searchInput.value = 'hello';
      searchInput.dispatchEvent(new Event('input'));

      vi.advanceTimersByTime(199);
      expect(window.location.hash).toBe(toBrowseHash('docs')); // not yet

      vi.advanceTimersByTime(1); // 200 ms total
      expect(window.location.hash).toBe(toSearchHash('hello', 'docs'));
    });

    it('resets the debounce window on each keystroke (only the last value searches)', async () => {
      const { searchInput } = setupSearchWrapper({ hash: toBrowseHash('docs') });
      await flush();
      vi.useFakeTimers();

      searchInput.value = 'a';
      searchInput.dispatchEvent(new Event('input'));
      vi.advanceTimersByTime(150); // first timer has 50 ms left

      searchInput.value = 'ab';
      searchInput.dispatchEvent(new Event('input')); // cancels first, starts fresh
      vi.advanceTimersByTime(150); // 150 ms since last keystroke — still inside
      expect(window.location.hash).toBe(toBrowseHash('docs'));

      vi.advanceTimersByTime(50); // 200 ms since last keystroke
      expect(window.location.hash).toBe(toSearchHash('ab', 'docs'));
    });

    it('trims the query before navigating to the search hash', async () => {
      const { searchInput } = setupSearchWrapper({ hash: toBrowseHash('docs') });
      await flush();
      vi.useFakeTimers();

      searchInput.value = '   spaced   ';
      searchInput.dispatchEvent(new Event('input'));

      vi.advanceTimersByTime(200);
      expect(window.location.hash).toBe(toSearchHash('spaced', 'docs'));
    });

    it('a second debounce can fire after the first one completes', async () => {
      // Guards against a regression where the timer variable is not reset to
      // null after firing, which would block subsequent searches.
      const { searchInput } = setupSearchWrapper({ hash: toBrowseHash('docs') });
      await flush();
      vi.useFakeTimers();

      searchInput.value = 'a';
      searchInput.dispatchEvent(new Event('input'));
      vi.advanceTimersByTime(200); // first search fires
      expect(window.location.hash).toBe(toSearchHash('a', 'docs'));

      searchInput.value = 'ab';
      searchInput.dispatchEvent(new Event('input'));
      vi.advanceTimersByTime(199);
      expect(window.location.hash).toBe(toSearchHash('a', 'docs')); // not yet
      vi.advanceTimersByTime(1);
      expect(window.location.hash).toBe(toSearchHash('ab', 'docs'));
    });
  });

  describe('Enter key (immediate search, no debounce)', () => {
    it('triggers search immediately on Enter (no 200 ms wait)', async () => {
      const { searchInput } = setupSearchWrapper({ hash: toBrowseHash('docs') });
      await flush();

      searchInput.value = 'foo';
      searchInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter' }));

      expect(window.location.hash).toBe(toSearchHash('foo', 'docs'));
    });

    it('does not stop propagation on Enter', () => {
      // Only Escape stops propagation; Enter must not, so it cannot interfere
      // with any upstream keydown handling.
      const { searchInput } = setupSearchWrapper();
      const event = new KeyboardEvent('keydown', { key: 'Enter' });
      const stopSpy = vi.spyOn(event, 'stopPropagation');

      searchInput.dispatchEvent(event);

      expect(stopSpy).not.toHaveBeenCalled();
    });
  });

  describe('Escape key (clear + stopPropagation)', () => {
    it('clears the search input value on Escape', () => {
      const { searchInput } = setupSearchWrapper({ hash: toSearchHash('foo', 'docs') });
      searchInput.value = 'foo';

      searchInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Escape' }));

      expect(searchInput.value).toBe('');
    });

    it('navigates back to the browse view for the current path on Escape', () => {
      setupSearchWrapper({ hash: toSearchHash('foo', 'docs') });

      const searchInput = document.querySelector('.search-wrapper input[type="text"]')!;
      searchInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Escape' }));

      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });

    it('stops propagation on Escape (so an enclosing dialog is not dismissed)', () => {
      // The search input may live inside a <dialog> (when the browser modal is
      // open). Without stopPropagation, the native dialog ESC-to-close behavior
      // would fire and dismiss the dialog. The handler must swallow the Escape
      // so it only clears the search.
      const { searchInput } = setupSearchWrapper();
      const event = new KeyboardEvent('keydown', { key: 'Escape' });
      const stopSpy = vi.spyOn(event, 'stopPropagation');

      searchInput.dispatchEvent(event);

      expect(stopSpy).toHaveBeenCalled();
    });

    it('clears before stopPropagation order does not matter (both effects occur)', () => {
      const { searchInput } = setupSearchWrapper({ hash: toSearchHash('bar', 'docs') });
      searchInput.value = 'bar';
      const event = new KeyboardEvent('keydown', { key: 'Escape' });
      vi.spyOn(event, 'stopPropagation');

      searchInput.dispatchEvent(event);

      expect(searchInput.value).toBe('');
      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });
  });

  describe('clear button click', () => {
    it('clears the search input value when the clear button is clicked', () => {
      const { searchClearBtn, searchInput } = setupSearchWrapper({
        hash: toSearchHash('foo', 'docs'),
      });
      searchInput.value = 'foo';

      searchClearBtn.click();

      expect(searchInput.value).toBe('');
    });

    it('navigates back to the browse view for the current path on clear click', () => {
      const { searchClearBtn } = setupSearchWrapper({ hash: toSearchHash('foo', 'docs') });

      searchClearBtn.click();

      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });
  });
});

/* ===========================================================================
 * DomRefs: init receives exactly the 5 standard refs
 *
 * The clear-button visibility is driven purely by CSS (:placeholder-shown on
 * the input), so startApp must NOT add searchWrapper or searchClearBtn to the
 * refs object it hands to init. Pinning the exact key set guards against a
 * regression that threads the new nodes through the shared context.
 * ========================================================================= */
describe('startApp search area: DomRefs unchanged', () => {
  it('passes exactly the 5 standard refs to init (no searchWrapper / clearBtn)', () => {
    const { searchInput, uploadInput, results, status, breadcrumb } = setupSearchWrapper();

    expect(init).toHaveBeenCalledTimes(1);
    const refs = vi.mocked(init).mock.calls[0][0];
    expect(Object.keys(refs).sort()).toEqual([
      'breadcrumb',
      'results',
      'searchInput',
      'status',
      'uploadInput',
    ]);
    // The refs point at the actual rendered nodes (not clones/duplicates).
    expect(refs.results).toBe(results);
    expect(refs.status).toBe(status);
    expect(refs.breadcrumb).toBe(breadcrumb);
    expect(refs.searchInput).toBe(searchInput);
    expect(refs.uploadInput).toBe(uploadInput);
  });

  it('does not attach a separate clear-button listener via the context (no getSearchClearBtn)', async () => {
    // The context module exposes getters only for the 5 standard refs. The
    // clear-button click handler is wired directly in startApp (imperative
    // addEventListener), not through a context ref — so importing the context
    // must not surface a clear-button getter. This is a structural guard: if a
    // future change adds the clear button to DomRefs, a matching getter would
    // appear here.
    const ctx = await import('./context');
    expect(typeof (ctx as Record<string, unknown>).getSearchClearBtn).toBe('undefined');
    expect(typeof (ctx as Record<string, unknown>).getSearchWrapper).toBe('undefined');
  });
});

/**
 * Tests for the toolbar handlers — the search button / Enter-key handler, the
 * clear-search handler, and the upload (change) handler, including the
 * per-file upload error-handling contract.
 *
 * Split out of the former `src/app.test.ts` monolith (task-29). Shared
 * fixtures, DOM scaffolding, and the per-test fetch stub come from
 * `./test-helpers`.
 *
 * Environment: the project-default `happy-dom` (these tests need a DOM).
 */
import { describe, it, expect } from 'vitest';
import { toBrowseHash, toSearchHash } from '../router';
import { normalizeRelativePath } from '../format';
import { mockResponse } from '../test-utils/mock-response';
import {
  setup,
  flush,
  browseResult,
  fileEntry,
  joinPathHelper,
  fetchMock,
  installAppTestLifecycle,
} from './test-helpers';
import { clearSearch, pickAndUploadInto } from './toolbar-handlers';

installAppTestLifecycle();

/* ===========================================================================
 * Toolbar handlers
 * ========================================================================= */
describe('toolbar handlers', () => {
  describe('search', () => {
    it('navigates to a search hash for the input value and current path when the Search button is clicked', async () => {
      const { searchInput, searchBtn } = setup({ hash: toBrowseHash('docs') });
      await flush();

      searchInput.value = 'hello world';
      searchBtn.click();

      expect(window.location.hash).toBe(toSearchHash('hello world', normalizeRelativePath('docs')));
    });

    it('trims the query before navigating', async () => {
      const { searchInput, searchBtn } = setup({ hash: toBrowseHash('docs') });
      await flush();

      searchInput.value = '   spaced   ';
      searchBtn.click();

      expect(window.location.hash).toBe(toSearchHash('spaced', 'docs'));
    });

    it('clears the search (returns to browse) when the query is empty', async () => {
      const { searchInput, searchBtn } = setup({ hash: toSearchHash('foo', 'docs') });
      await flush();

      searchInput.value = '';
      searchBtn.click();

      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });

    it('clears the search when the query is only whitespace', async () => {
      const { searchInput, searchBtn } = setup({ hash: toSearchHash('foo', 'docs') });
      await flush();

      searchInput.value = '   \t  ';
      searchBtn.click();

      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });

    it('navigates when Enter is pressed inside the search input', async () => {
      const { searchInput } = setup({ hash: toBrowseHash('docs') });
      await flush();

      searchInput.value = 'foo';
      searchInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter' }));

      expect(window.location.hash).toBe(toSearchHash('foo', 'docs'));
    });
  });

  describe('clearSearch', () => {
    // clearSearch() is the explicit "clear the search box and return to browse"
    // handler (e.g. an "×" / Clear button). It must (1) blank the shared search
    // input, (2) read the CURRENT route's path, and (3) navigate to the browse
    // hash for that path — mirroring doSearch()'s empty-query branch, but as a
    // dedicated, unconditional entry point that also wipes the input text.

    it('resets the search input value to an empty string', async () => {
      const { searchInput } = setup({ hash: toSearchHash('foo', 'docs') });
      await flush();

      searchInput.value = 'leftover query';
      clearSearch();
      await flush();

      expect(searchInput.value).toBe('');
    });

    it('navigates to the browse hash for the current browse path', async () => {
      setup({ hash: toBrowseHash('docs/sub') });
      await flush();

      clearSearch();
      await flush();

      expect(window.location.hash).toBe(toBrowseHash(normalizeRelativePath('docs/sub')));
    });

    it('uses the current route path even when the app is showing a search view', async () => {
      // A search route carries its own `path` (the search scope); clearSearch
      // must drop the query and return to browsing THAT path, not root.
      setup({ hash: toSearchHash('anything', 'docs') });
      await flush();

      clearSearch();
      await flush();

      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });

    it('normalizes the current path before building the browse hash', async () => {
      // A trailing slash (or backslashes) in the current path is collapsed by
      // normalizeRelativePath so the resulting browse hash is canonical.
      setup({ hash: toBrowseHash('docs/') });
      await flush();

      clearSearch();
      await flush();

      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });

    it('navigates to the root browse hash when the current path is empty', async () => {
      setup({ hash: '' });
      await flush();

      clearSearch();
      await flush();

      expect(window.location.hash).toBe(toBrowseHash(''));
    });

    it('clears the input and navigates to browse together', async () => {
      const { searchInput } = setup({ hash: toSearchHash('foo', 'docs') });
      await flush();

      searchInput.value = 'stale text';
      clearSearch();
      await flush();

      expect(searchInput.value).toBe('');
      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });
  });

  describe('upload', () => {
    function setFiles(input: HTMLInputElement, names: string[]): void {
      const dt = new DataTransfer();
      for (const n of names) dt.items.add(new File(['data-' + n], n));
      input.files = dt.files as unknown as FileList;
    }

    /** Drain queued microtasks enough times for the upload loop + re-render. */
    const settle = async (n = 10): Promise<void> => {
      for (let i = 0; i < n; i++) await flush();
    };

    /**
     * Build a fetch impl that rejects POST /upload for the named files (via a
     * non-ok Response, exactly how `ApiClient.request` surfaces failures) while
     * still serving normal browse/upload responses for everything else.
     */
    function failingUploadImpl(failingNames: string[]) {
      const failing = new Set(failingNames);
      return async (url: string, init?: RequestInit): Promise<Response> => {
        const u = String(url);
        const method = (init?.method ?? 'GET').toUpperCase();
        if (method === 'POST' && u.includes('/upload')) {
          const file = (init?.body as FormData | undefined)?.get('file') as File | null;
          if (file && failing.has(file.name)) {
            return mockResponse({ ok: false, status: 413, text: 'too large' });
          }
          return mockResponse({ status: 200, body: { path: file?.name ?? '' } });
        }
        if (method === 'GET' && u.includes('/browse')) {
          const raw = u.split('path=')[1] ?? '';
          const path = decodeURIComponent(raw);
          const child = 'child-of-' + (path || 'root');
          return mockResponse({
            body: browseResult({
              path,
              entries: [fileEntry({ name: child, path: joinPathHelper(path, child) })],
              fileCount: 1,
              totalSize: 10,
            }),
          });
        }
        return mockResponse({ status: 200, body: {} });
      };
    }

    /** Ordered names of files POSTed to /upload so far. */
    function uploadedFileNames(): string[] {
      return fetchMock.mock.calls
        .filter(([u, init]) => String(u).includes('/upload') && (init?.method ?? 'GET') === 'POST')
        .map(
          ([, init]) =>
            ((init?.body as FormData | undefined)?.get('file') as File | null)?.name ?? '',
        );
    }

    /** Count of GET /browse calls observed so far. */
    function browseCount(): number {
      return fetchMock.mock.calls.filter(
        ([u, init]) => String(u).includes('/browse') && (init?.method ?? 'GET') === 'GET',
      ).length;
    }

    it('uploads each selected file to the current browse path, then clears the input and re-renders', async () => {
      const { uploadInput } = setup({ hash: toBrowseHash('docs') });
      await flush();

      setFiles(uploadInput, ['a.txt', 'b.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await flush();
      await flush();

      const uploadCalls = fetchMock.mock.calls.filter(
        ([u, init]) => String(u).includes('/upload') && (init?.method ?? 'GET') === 'POST',
      );
      expect(uploadCalls).toHaveLength(2);
      for (const [, init] of uploadCalls) {
        expect(init?.body).toBeInstanceOf(FormData);
        expect((init!.body as FormData).get('file')).toBeInstanceOf(File);
      }
      // All uploads target the current browse path.
      expect(
        uploadCalls.every(([u]) => String(u).includes('path=' + encodeURIComponent('docs'))),
      ).toBe(true);
      // The input is cleared afterwards.
      expect(uploadInput.value).toBe('');
      // And a re-render occurred (browse fetched again after upload).
      const browseCalls = fetchMock.mock.calls.filter(([u]) => String(u).includes('/browse'));
      expect(browseCalls.length).toBeGreaterThan(0);
    });

    it('uploads nothing when no files are selected', async () => {
      const { uploadInput } = setup({ hash: toBrowseHash('docs') });
      await flush();

      uploadInput.dispatchEvent(new Event('change'));
      await flush();

      expect(fetchMock.mock.calls.some(([u]) => String(u).includes('/upload'))).toBe(false);
    });

    // ---- per-file error handling -------------------------------------------
    // A single failing upload must NOT abort the remaining uploads, swallow the
    // re-render, or leave the input uncleared. Each failure is surfaced in the
    // status footer (see task spec: "Uploaded N file(s); failed: a.txt, b.txt").

    it('continues uploading the remaining files when a middle upload fails, then clears the input, re-renders, and surfaces the failure', async () => {
      fetchMock.mockImplementation(failingUploadImpl(['b.txt']));
      const { uploadInput, status } = setup({ hash: toBrowseHash('docs') });
      await flush();
      const browseBefore = browseCount();

      setFiles(uploadInput, ['a.txt', 'b.txt', 'c.txt']);
      uploadInput.dispatchEvent(new Event('change'));
